sql:
SELECT DISTINCT location 
FROM monitoring_stations 
INNER JOIN station_sensors ON monitoring_stations.station_id = station_sensors.station_id;

SELECT pollutant_name 
FROM pollutants 
WHERE pollutant_id = 1;

external_knowledge:
- "Lungs of each neighborhood" refers to the air quality;
- "Breathing in the quality of air" represents the air quality measurements;
- "Since the dawn of the decade" refers to the installation date before 2020;
- "Yearly coughs" metaphorically means the emergency department annual adult rate per 10,000 population;
- "The number of souls residing" refers to the population of the borough.
